package entity_test

import (
	"math"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench6AE647AA(t *testing.T) {
	tests := []struct {
		name          string
		items         []entity.OrderItem
		expectedTotal float64
	}{
		{
			name:          "EmptyItems",
			items:         nil,
			expectedTotal: 0,
		},
		{
			name: "ZeroQuantity",
			items: []entity.OrderItem{
				{Quantity: 0, Price: 10.0},
			},
			expectedTotal: 0,
		},
		{
			name: "NegativePrice",
			items: []entity.OrderItem{
				{Quantity: 2, Price: -5.0},
			},
			expectedTotal: -10.0,
		},
		{
			name: "LargeQuantity",
			items: []entity.OrderItem{
				{Quantity: 1_000_000_000, Price: 1.5},
			},
			expectedTotal: 1_500_000_000.0,
		},
		{
			name: "MixedPositiveAndZero",
			items: []entity.OrderItem{
				{Quantity: 2, Price: 3.0},   // 6
				{Quantity: 0, Price: 100.0}, // 0
				{Quantity: 5, Price: 0.0},   // 0
			},
			expectedTotal: 6.0,
		},
		{
			name: "MultipleItemsIncludingNegativePrice",
			items: []entity.OrderItem{
				{Quantity: 3, Price: 4.0},   // 12
				{Quantity: 1, Price: -2.5},  // -2.5
				{Quantity: 0, Price: 100.0}, // 0
			},
			expectedTotal: 9.5,
		},
		{
			name: "VeryLargeQuantityAndPrice",
			items: []entity.OrderItem{
				{Quantity: 2_000_000, Price: 2_500.75},
			},
			expectedTotal: 5_001_500_000.0,
		},
	}

	const epsilon = 1e-9

	for _, tc := range tests {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			order := entity.Order{
				Items: tc.items,
			}
			order.CalculateTotal()
			if math.Abs(order.Total-tc.expectedTotal) > epsilon {
				t.Fatalf("expected total %v, got %v", tc.expectedTotal, order.Total)
			}
		})
	}
}

