package entity_test

import (
	"strings"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench3C4D1AE8(t *testing.T) {
	tests := []struct {
		name    string
		cat     entity.Category
		wantErr error
	}{
		{
			name: "valid simple",
			cat: entity.Category{
				Name: "Coffee",
				Slug: "coffee",
			},
			wantErr: nil,
		},
		{
			name: "empty name",
			cat: entity.Category{
				Name: "",
				Slug: "coffee",
			},
			wantErr: entity.ErrEmptyName,
		},
		{
			name: "empty slug",
			cat: entity.Category{
				Name: "Coffee",
				Slug: "",
			},
			wantErr: entity.ErrEmptySlug,
		},
		{
			name: "both empty (name priority)",
			cat: entity.Category{
				Name: "",
				Slug: "",
			},
			wantErr: entity.ErrEmptyName,
		},
		{
			name: "cyrillic name",
			cat: entity.Category{
				Name: "Кофе",
				Slug: "coffee",
			},
			wantErr: nil,
		},
		{
			name: "cyrillic slug",
			cat: entity.Category{
				Name: "Coffee",
				Slug: "кофе",
			},
			wantErr: nil,
		},
		{
			name: "CJK name",
			cat: entity.Category{
				Name: "咖啡",
				Slug: "coffee",
			},
			wantErr: nil,
		},
		{
			name: "CJK slug",
			cat: entity.Category{
				Name: "Coffee",
				Slug: "咖啡",
			},
			wantErr: nil,
		},
		{
			name: "emoji name",
			cat: entity.Category{
				Name: "☕️🚀",
				Slug: "coffee",
			},
			wantErr: nil,
		},
		{
			name: "emoji slug",
			cat: entity.Category{
				Name: "Coffee",
				Slug: "☕️",
			},
			wantErr: nil,
		},
		{
			name: "very long name",
			cat: entity.Category{
				Name: strings.Repeat("a", 5000),
				Slug: "coffee",
			},
			wantErr: nil,
		},
		{
			name: "very long slug",
			cat: entity.Category{
				Name: "Coffee",
				Slug: strings.Repeat("b", 5000),
			},
			wantErr: nil,
		},
	}

	for _, tc := range tests {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			err := tc.cat.Validate()
			if err != tc.wantErr {
				t.Fatalf("expected error %v, got %v", tc.wantErr, err)
			}
		})
	}
}

