package entity_test

// CHOICE: NewsItem.Summary — testing edge case where maxRunes <=3 should not add ellipsis even when truncating.
import (
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench820FB329(t *testing.T) {
	tests := []struct {
		name       string
		content    string
		maxRunes   int
		wantResult string
	}{
		{
			name:       "truncate with maxRunes=3, longer ASCII content, no ellipsis",
			content:    "Hello, world!",
			maxRunes:   3,
			wantResult: "Hel",
		},
		{
			name:       "content exactly 3 runes, maxRunes=3, unchanged",
			content:    "abc",
			maxRunes:   3,
			wantResult: "abc",
		},
		{
			name:       "truncate multibyte emojis with maxRunes=3, no ellipsis",
			content:    "😀😁😂😃",
			maxRunes:   3,
			wantResult: "😀😁😂",
		},
		{
			name:       "maxRunes larger than content length, full content returned",
			content:    "Hi",
			maxRunes:   5,
			wantResult: "Hi",
		},
	}
	for _, tt := range tests {
		tt := tt
		t.Run(tt.name, func(t *testing.T) {
			ni := entity.NewsItem{
				Content: tt.content,
			}
			got := ni.Summary(tt.maxRunes)
			if got != tt.wantResult {
				t.Fatalf("Summary(%d) = %q, want %q", tt.maxRunes, got, tt.wantResult)
			}
		})
	}
}
